 *     "launchers": [
 *       {
 *         "id": "claude-usage-toolbar",
 *         "displayName": "Claude Usage",
 *         "placementZone": "toolbarButton",
 *         "action": { "type": "openModal", "target": "ClaudeUsageView" },
 *         "render": { "environment": "hostOverlay", "bounds": "wide" }
 *       }
 *     ]
 *   }
 * ]
 * ```
 *
 * Response: PluginUiContribution[]
 */
