import { Router } from "express";
import { exec, spawn } from "node:child_process";

const router = Router();

const SCRIPTS_DIR = "/app/scripts";

function vncRunning(): Promise<boolean> {
  return new Promise((resolve) => {
    exec("ss -tln | grep -q ':5900 '", (err) => resolve(!err));
  });
}

function chromiumReady(): Promise<boolean> {
  return new Promise((resolve) => {
    exec(
      "curl -s --max-time 2 http://127.0.0.1:9222/json/version > /dev/null 2>&1",
      (err) => resolve(!err),
    );
  });
}

function websockifyReady(): Promise<boolean> {
  return new Promise((resolve) => {
    exec("ss -tln | grep -q ':6080 '", (err) => resolve(!err));
  });
}

// GET /api/browser/status
router.get("/status", async (_req, res) => {
  const running = await vncRunning();
  const cdp = running ? (await chromiumReady()) && (await websockifyReady()) : false;
  res.json({ running, cdp });
});

// POST /api/browser/start
router.post("/start", (_req, res) => {
  const child = spawn("bash", [`${SCRIPTS_DIR}/vnc-start.sh`], {
    detached: true,
    stdio: "ignore",
  });
  child.unref();
  res.json({
    ok: true,
    message: "VNC stack starting — poll /status for readiness",
  });
});

// POST /api/browser/stop
router.post("/stop", (_req, res) => {
  exec(`${SCRIPTS_DIR}/vnc-stop.sh`, { timeout: 10000 }, (_err, stdout) => {
    res.json({ ok: true, message: (stdout ?? "").trim() });
  });
});

export default router;

